import ScrollAnimation from 'react-animate-on-scroll';
import React, {useState} from "react";
import styled, { keyframes } from 'styled-components';
import Hobbies from './Hobbies';
import LanguageList from "./LanguageList";
import HistoryOfMe from "./HistoryOfMe";
import "grid-css/grid.min.css";
import ReactPlayer from 'react-player'
import { slideInLeft, slideInRight,fadeIn,fadeOut } from 'react-animations';
function AboutMe() {
    const [isShown, SetIsShown] = useState(0);
    const [isVidShown,SetVidShown] = useState(0);
    const SlideInLeft = styled.div`animation: 2s ${keyframes`${slideInLeft}`} infinite `;
    const SlideInLeftOnce = styled.div`animation: 2s ${keyframes`${slideInLeft}`} 1 `;
    const SlideInRight = styled.div`animation: 2s ${keyframes`${slideInRight}`} infinite `;
    const FadeIn = styled.div`animation: 0.5s ${keyframes`${fadeIn}`} 1 `;
    const FadeOut = styled.div`animation: 0.5s ${keyframes`${fadeOut}`} 1 `;
    return(
        <ScrollAnimation
            animateIn='fadeIn'
            animateOut='fadeOut'>
            <div className="ui center aligned segment">

                <h1 className="ui header" style={{fontWeight:"900"}}>
                    <SlideInLeft style={{display:"inline-block"}}>
                        <i className="caret right icon" style={{textAlign:"left",fontSize:"1em"}}/>
                    </SlideInLeft>
                    About Me
                    <SlideInRight style={{display:"inline-block"}}>
                        <i className="caret left icon" style={{textAlign:"right",fontSize:"1em"}}/>
                    </SlideInRight>
                </h1>

            </div>
            <div className="ui left aligned segment">
                <h2 className="ui header">Skill Set</h2>
                <div className="grid assessmentList">
                    <div className="cell"></div>
                    <div className="cell">Beginner</div>
                    <div className="cell">Elementary</div>
                    <div className="cell">Intermediate</div>
                    <div className="cell">Advanced</div>
                    <div className="cell">Expert</div>
                </div>

                <SlideInLeftOnce>
                    <LanguageList/>
                </SlideInLeftOnce>

                <Hobbies/>
            </div>
            <HistoryOfMe/>
            <div className="ui center aligned segment">
                <h1 className="ui header" style={{fontWeight:"900"}}>
                    <SlideInLeft style={{display:"inline-block"}}>
                        <i className="caret right icon" style={{textAlign:"left",fontSize:"1em"}}/>
                    </SlideInLeft>
                    Projects
                    <SlideInRight style={{display:"inline-block"}}>
                        <i className="caret left icon" style={{textAlign:"right",fontSize:"1em"}}/>
                    </SlideInRight>
                </h1>
            </div>
            <div className="ui center aligned segment">
                <div className="grid">
                    <div className="cell">
                        {isVidShown==1 && (
                            <ReactPlayer
                                url="./videos/Helicopter_Demo.MP4"
                                width='40vw'
                                height='40vh'
                                controls={true}
                                onMouseEnter={() => (SetIsShown(1),SetVidShown(0))}
                                onMouseLeave={() => (SetIsShown(0),SetVidShown(1))}
                                className="demo-vid-1"
                            ></ReactPlayer>
                        )
                        }

                        {isShown == 1 && (
                            <div>
                                <FadeIn>
                                    <div className="ui white segment demo1" style={{position:"absolute",width: "40vw", height: "40vh"}}></div>
                                </FadeIn>
                            </div>
                        )
                        }



                    </div>
                    <div className="cell"
                         onMouseEnter={() => SetIsShown(2)}
                         onMouseLeave={() => SetIsShown(0)}
                    >
                        {isShown == 2 && (
                            <FadeIn>
                                <div class="ui white segment" style={{left:"51.9vw",position:"absolute",width:"40vw",height:"40vh"}}></div>
                            </FadeIn>
                        )

                        }
                        <ReactPlayer
                            url="./videos/Solar_System_Demo.MP4"
                            width='40vw'
                            height='40vh'
                            controls={true}
                        ></ReactPlayer>
                    </div>
                </div>
            </div>
        </ScrollAnimation>

    )
};
export default AboutMe;
